<script>
import RecomList from "@/components/RecomList";
import ShopList from '@/components/ShopList'
export default {
  components:{
  ShopList,
  RecomList
  },
  data(){
    return{
    keywords:[],
    word:'',
    proList:[],
    recom:[]
    }
  },
  created(){
    this.axios.get('/api/search/keyword').then(d=>{
      this.keywords = d.data.data;
    });
    // 推荐商品
    this.axios.get("/api/index").then((da) => {
      this.recom = da.data.data.info.bastList.slice(0, 9);
      console.log(this.recom);
    });
  },
  methods:{
    search(){
      this.axios.get('/api/products?page=1&limit=20&keyword='+this.word).then(d=>{
      console.log(d.data.data);
        this.proList = d.data.data;
    })
    }
  }
}
</script>

